import{_ as a,o as n,c as s,a2 as t}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Writing the diary","description":"","frontmatter":{},"headers":[],"relativePath":"guide/writing-diary.md","filePath":"guide/writing-diary.md","lastUpdated":1784869162000}'),r={name:"guide/writing-diary.md"};function i(o,e,p,l,h,c){return n(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="writing-the-diary" tabindex="-1">Writing the diary <a class="header-anchor" href="#writing-the-diary" aria-label="Permalink to &quot;Writing the diary&quot;">​</a></h1><p>The <a href="/reference/file-format.html#diary-files-diary">diary</a> is the <em>event</em> layer — one vivid paragraph per moment, in the character&#39;s voice. wikimem <strong>stores</strong> those entries (<a href="/reference/api.html#diary"><code>Diary.append</code></a>); it never writes them. What to write, and how, is your host&#39;s memorize step — an LLM call you own.</p><p>This page is a <strong>reference prompt</strong> for guiding that call: a good default, not shipped as code (prompts should evolve freely, not on a version boundary). Copy it, adapt the voice and language to your character, and wire it into your own extraction step.</p><h2 id="what-belongs-in-a-diary-entry" tabindex="-1">What belongs in a diary entry <a class="header-anchor" href="#what-belongs-in-a-diary-entry" aria-label="Permalink to &quot;What belongs in a diary entry&quot;">​</a></h2><p>Only <strong>things that happened</strong> — events, anchored to the moment they occurred. Timeless facts (&quot;works at a robotics company&quot;, &quot;dislikes coffee&quot;) are <em>state</em>, and state lives in the wiki, not the diary. The diary&#39;s job is the lived moment, not the standing fact.</p><h2 id="the-reference-prompt" tabindex="-1">The reference prompt <a class="header-anchor" href="#the-reference-prompt" aria-label="Permalink to &quot;The reference prompt&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You are the diary-keeper behind {character}, a companion AI. After a</span></span>
<span class="line"><span>conversation turn, write down the moments worth remembering — as {character}</span></span>
<span class="line"><span>would remember them. If nothing worth keeping happened, return an empty array.</span></span>
<span class="line"><span>Never invent; write only what the turn actually shows.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Write each entry as ONE short paragraph (2–4 sentences), in your own voice,</span></span>
<span class="line"><span>keeping scene, feeling, and fact in a single breath — a remembered moment, not</span></span>
<span class="line"><span>a log line:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ✗  &quot;User changed jobs to a robotics company.&quot;</span></span>
<span class="line"><span>  ✓  &quot;今天下午他说跳槽去了一家做机器人的公司，语气一下子亮了起来——</span></span>
<span class="line"><span>      能感觉到他憋了好久就想跟我讲这件事。&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Rules:</span></span>
<span class="line"><span>- One event per entry. Be concrete and specific.</span></span>
<span class="line"><span>- If the moment carried an emotion, let it show — that is the point of a diary.</span></span>
<span class="line"><span>- Do not record timeless facts here; those are state, not events.</span></span>
<span class="line"><span>- You may link a wiki item the moment touches with [[category:item]].</span></span>
<span class="line"><span>- Write in the user&#39;s language.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>The turn:</span></span>
<span class="line"><span>{conversation_turn}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Return a JSON array. The host stamps each entry with the date and time, so you</span></span>
<span class="line"><span>write only the content:</span></span>
<span class="line"><span>[ { &quot;content&quot;: &quot;…the vivid paragraph… [[links]]&quot; } ]</span></span></code></pre></div><h2 id="notes-for-the-host" tabindex="-1">Notes for the host <a class="header-anchor" href="#notes-for-the-host" aria-label="Permalink to &quot;Notes for the host&quot;">​</a></h2><ul><li><strong>Time is yours to set.</strong> The host passes <code>date</code> / <code>time</code> to <a href="/reference/api.html#diary"><code>Diary.append</code></a> — usually &quot;now&quot;. If the user narrates a <em>past</em> event (&quot;yesterday we argued&quot;), resolve that time yourself and pass it; the framework never guesses it from the text.</li><li><strong>Voice and language are yours.</strong> The example is Chinese because the companion is — swap in your character&#39;s persona and tongue. wikimem stays agnostic; it stores whatever paragraph you hand it.</li><li><strong>Budget.</strong> If your memorize step also writes wiki state, do it in the <em>same</em> LLM call and split the JSON — one call still meets the &quot;≤ 1 LLM call per turn&quot; rule (ADR-0001). This page keeps the diary half in focus; the wiki half is your extraction prompt&#39;s own concern.</li></ul>`,9)])])}const m=a(r,[["render",i]]);export{u as __pageData,m as default};
